real_t s172(struct args_t * func_args)
{
    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    for (int nl = 0; nl < iterations; nl++) {
        if (n3 != 0) {
            int start = n1 - 1;
            int end = LEN_1D;

            if (start < end) {
                // Handle the first element separately to align subsequent blocks
                a[start] += b[start];

                // Process the rest in contiguous chunks of size n3
                // This transforms the strided loop into a series of vectorizable loops
                for (int offset = 1; offset < n3; offset++) {
                    int base = start + offset;
                    if (base < end) {
                        // Inner loop with stride 1 is trivially vectorizable
                        for (int i = base; i < end; i += n3) {
                            a[i] += b[i];
                        }
                    }
                }
            }
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s1113(struct args_t * func_args)
{

//    linear dependence testing
//    one iteration dependency on a(LEN_1D/2) but still vectorizable

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    for (int nl = 0; nl < 2*iterations; nl++) {
        real_t temp = a[LEN_1D/2];
        for (int i = 0; i < LEN_1D; i++) {
            a[i] = temp + b[i];
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s122(struct args_t * func_args)
{

//    induction variable recognition
//    variable lower and upper bound, and stride
//    reverse data access and jump in data access

    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    int j, k;
    for (int nl = 0; nl < iterations; nl++) {
        j = 1;
        // k is initialized to 0 before the loop.
        // Inside the loop: k += j, where j is constant 1.
        // Iteration 0 (i = n1-1): k = 0 + 1 = 1
        // Iteration 1 (i = n1-1+n3): k = 1 + 1 = 2
        // Iteration t: k = t + 1
        // Since i = n1 - 1 + t * n3, we have t = (i - (n1 - 1)) / n3.
        // Therefore, k = (i - (n1 - 1)) / n3 + 1.
        // This transformation removes the loop-carried dependency on k.

        int start_i = n1 - 1;
        for (int i = start_i; i < LEN_1D; i += n3) {
            k = (i - start_i) / n3 + 1;
            a[i] += b[LEN_1D - k];
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}
